import React, { Component } from "react"
import "../css/comments.scss"
import api from "../api"
import { CommentsItem } from "../components/comment-item";
import { connect } from "react-redux";
import { getLongComments, getShortComments, hideBox, initComments } from "../redux/action"
import {Toast} from "antd-mobile"
@connect(
    state => {
        return {
            data: state.comments_data
        }
    }
)
export class Comments extends Component {
    componentWillMount() {
        let { dispatch, match } = this.props
        let { loading } = this.props.data;
        let id = match.params.id
        dispatch(getLongComments(`${api.GET_COMMENTS}${id}/long-comments`))
        if (loading) {
            Toast.loading('正在加载中...');
        } else {
            Toast.hide();
        }
        window.addEventListener('scroll', this.getScrollData, false)
    }
    goBack() {
        window.history.back()
    }
    getShortComments = () => {
        let { dispatch, match } = this.props;
        let id = match.params.id
        dispatch(getShortComments(`${api.GET_COMMENTS}${id}/short-comments`))
        let { loading } = this.props.data;
        if (loading) {
            Toast.loading('正在加载中...');
        } else {
            Toast.hide();
        }
    }
    componentWillUnmount() {
        let { dispatch } = this.props
        dispatch(initComments())
    }
    render() {
        let extra = JSON.parse(window.sessionStorage.extra)
        let { data } = this.props
        let { dispatch } = this.props
        return (
            <div>
                <div className="comments-header">
                    <div className="header-icon" onClick={this.goBack}><i className="iconfont icon-fanhui"></i></div>
                    <div className="header-cont"><p><span></span>{extra.comments} 条点评</p></div>
                    <div className="header-icon"><i className="iconfont">&#xe648;</i><span></span></div>
                </div>
                <ul className="long-comments">
                    <li className="long-comments-nav"><span>{extra.long_comments}</span> 条长评</li>
                    {(() => {
                        if (data.long_comments && data.long_comments.length === 0) {
                            return (
                                <div className="no-comments">
                                    <div className="no-comments-icon">
                                        <i className="iconfont icon-shafa"></i>
                                        <p>深度长评虚位以待</p>
                                    </div>
                                </div>
                            )
                        }
                    })()}

                    {data.long_comments.map(item =>
                        <CommentsItem key={item.id} item={item}></CommentsItem>
                    )}
                </ul>


                <ul className="short-comments" id="short-comments-top">
                    <li className="short-comments-nav" onClick={this.getShortComments}><span>{extra.short_comments}</span> 条短评 <i className="iconfont">&#xe515;</i></li>
                    {data.short_comments.map(item =>
                        <CommentsItem key={item.id} item={item} ></CommentsItem>
                    )}
                </ul>
                {/*<!--操作框-->*/}
                {(() => {
                    if (data.show_box) {
                        return (
                            <div className="mask" onClick={() => { dispatch(hideBox()) }}>
                                <div className="reply-box" >
                                    <p>赞同</p>
                                    <p>举报</p>
                                    <p>复制</p>
                                    <p>回复</p>
                                </div>
                            </div>
                        )
                    }
                })()}
            </div>
        )
    }
}


