const initState = {
    body: '',
    image_source: '',
    loading: false,
    title: '',
    image: '',
    collection: false,
    show_share: false,
    section: {
        name: ''
    }
}

export const detailContent = (state = initState, action) => {
    switch (action.type) {
        case 'FETCH_DATA_SUCCESS':
            return Object.assign({}, state, action.data.DES, { loading: false })
            break;
        case 'FETCH_DATA_START':
            return {
                ...state,
                loading: true
            }
            break;
        case "FETCH_CONTENT_DATA_START":
            return {
                ...state,
                loading: true
            }
            break;
        case "FETCH_CONTENT_DATA_SUCCESS":
            return Object.assign({}, state, action.data.CONTENTS, { loading: false })
            break;
        case "INIT_DETAIL_DATA":
            return Object.assign({}, initState)
            break;
        case 'SHOW_COLLECTION':
            return {
                ...state,
                collection: true
            }
            break;
        case 'HIDE_COLLECTION':
            return {
                ...state,
                collection: false
            }
            break;
        case 'SHOW_SHARE':
            return {
                ...state,
                show_share: true
            }
            break;
        case 'HIDE_SHARE':
            return {
                ...state,
                show_share: false
            }
            break;
        default:
            return state
    }
}


