import React, { Component } from "react";
import { Link } from "react-router-dom";
import filter from "../util/filter.js"
import { connect } from "react-redux";
import "../css/list-item.scss"
export class ListItem extends Component {
    render() {
        let { dispatch } = this.props
        let item = this.props.item;
        let titleBOX=item.images?{ width: "4.4rem",flexWrap: "wrap",fontSize: "0.34rem"}:{  minWidth:"4.4rem",flexWrap: "wrap",fontSize: "0.34rem"}
        return (
            <Link to={`/detail/${item.id}`} className="list-item-wrap">
                <div className="list-detail-box">
                    <li className="list-content-box">
                        <div className="list-title-box" style={titleBOX}>{item.title}</div>
                        {
                            (() => {
                                if (item.display_date) {
                                    return <p className="time" >{item.display_date}</p>
                                }
                            })()
                        }

                        {(() => {
                            if (item.images) {
                                return (
                                    <div className="list-img-box">
                                        <img src={filter.replaceUrl(item.images[0])} alt="" />
                                        {(() => {
                                            if (item.multipic) {
                                                return
                                                <p className="tip">
                                                    <i className="iconfont">&#xe61c;</i>多图
                                                </p>
                                            }
                                        })()}
                                    </div>
                                )
                            }
                        })()}
                    </li>
                </div>
            </Link>
        )
    }
}


