const initState = {
    long_comments: [],
    short_comments: [],
    loading: false,
    show_box: false
}

export const commentsData = (state = initState, action) => {
    switch (action.type) {
        case 'GET_LONG_COMMENTS_SUCCESS':
            return {
                ...state,
                long_comments: action.data.COMMENTS.comments,
                loading: false
            }
            break;
        case "GET_SHORT_COMMENTS_SUCCESS":
            return Object.assign({}, {
                ...state,
                short_comments: action.data.COMMENTS.comments,
                loading: false,
                id: action.data.COMMENTS.comments[action.data.COMMENTS.comments.length - 1].id
            })
        case 'FETCH_DATA_START':
            return Object.assign({}, {
                ...state,
                loading: true
            })
            break;
        case "SHOW_BOX":
            return Object.assign({}, {
                ...state,
                show_box: true
            })
            break;
        case "HIDE_BOX":
            return Object.assign({}, {
                ...state,
                show_box: false
            })
            break;
        case "INIT_COMMENTS":
            return Object.assign({}, initState)
            break;
        default:
            return state;
            break;
    }
}


