

const initState = {
    loading: false,
    date: "",
    all_stories: [],
    top_stories: [],
    theme_stories: {
        stories: [],
        background: "",
        editors: []
    },
    night_style: false
}

export const contentList = (state = initState, action) => {
    switch (action.type) {
        case "CHANGE_MODE":
        console.log(1111)
            return Object.assign({}, state, {
                ...state,
                night_style: !state.night_style
            })
        case "GET_NEXT_NEWS_BEFORE":
            return Object.assign({}, state, {
                ...state,
                loading: true
            })
        case "GET_NEXT_NEWS_SUCCESS":
            return Object.assign({}, state, {
                ...state,
                loading: false,
                date: action.data.STORIES.date,
                all_stories: state.all_stories.concat(action.data.STORIES)
            })
        case 'GET_CONTENT_LIST':
        case 'GET_CONTENT_LIST_SUCCESS':
            return Object.assign({}, state, {
                all_stories: [].concat(action.data.STORIES),
                top_stories: [].concat(action.data.STORIES.top_stories),
                date: action.data.STORIES.date,
                loading: false
            })
            break;
        case "GET_THEME_SUCCESS":
            return Object.assign({}, state, {
                ...state,
                loading: false,
                theme_stories: action.data.THEMEDES
            })
        default:
            return state
            break;
    }
}


