import React, { Component } from "react";
import api from "../api"
import filter from "../util/filter"
import { Slider } from "./slider"
import { getContentData, getNextNews } from "../redux/action";
import { connect } from "react-redux";
import { ListItem } from "./list-item";
import "../css/list-default.scss"
import { PullToRefresh, Toast } from "antd-mobile"
@connect(
    state => {
        return {
            all_stories: state.content_list.all_stories,
            date: state.content_list.date,
            top_stories: state.content_list.top_stories,
            loading: state.content_list.loading,
        }
    }
)
export class ListDefault extends Component {
    constructor(props) {
        super(props);
        this.state = {
            refreshing: false,
            down: true,
            height: document.documentElement.clientHeight + 45,
            refreshing: false,
        };
    }
    componentDidMount() {
        let { loading } = this.props
        if (loading) {
            Toast.loading('正在加载中...');
        } else {
            Toast.hide();
        }
        let { dispatch } = this.props;
        dispatch(getContentData(api.LATEST_NEWS))
        window.addEventListener('scroll', this.getScrollList, false)
    }
    componentWillUnmount() {
        window.addEventListener('scroll', this.getScrollList, false)
    }
    getScrollList = (event) => {
        let { dispatch } = this.props
        let { loading } = this.props
        if (getScrollHeight() - 100 < getDocumentTop() + getWindowHeight() && !this.props.loading) {
            dispatch(getNextNews(api.NEXT_NEWS + this.props.date))
        }
        if (loading) {
            Toast.loading('正在加载中...');
        } else {
            Toast.hide();
        }
        function getDocumentTop() {
            var scrollTop = 0, bodyScrollTop = 0, documentScrollTop = 0;
            if (document.body) {
                bodyScrollTop = document.body.scrollTop;
            }
            if (document.documentElement) {
                documentScrollTop = document.documentElement.scrollTop;
            }
            scrollTop = (bodyScrollTop - documentScrollTop > 0) ? bodyScrollTop : documentScrollTop;
            return scrollTop;
        }

        //可视窗口高度
        function getWindowHeight() {
            var windowHeight = 0;
            if (document.compatMode == "CSS1Compat") {
                windowHeight = document.documentElement.clientHeight;
            } else {
                windowHeight = document.body.clientHeight;
            }
            return windowHeight;
        }

        //滚动条滚动高度
        function getScrollHeight() {
            var scrollHeight = 0, bodyScrollHeight = 0, documentScrollHeight = 0;
            if (document.body) {
                bodyScrollHeight = document.body.scrollHeight;
            }
            if (document.documentElement) {
                documentScrollHeight = document.documentElement.scrollHeight;
            }
            scrollHeight = (bodyScrollHeight - documentScrollHeight > 0) ? bodyScrollHeight : documentScrollHeight;
            return scrollHeight;
        }

    }
    render() {
        let { dispatch, all_stories } = this.props

        return (
            <div className="main-list">
                <PullToRefresh
                    damping={60}
                    ref={el => this.ptr = el}
                    style={{
                        height: this.state.height,
                        overflow: 'auto',
                    }}
                    indicator={this.state.down ? {} : { deactivate: '上拉可以刷新' }}
                    direction={this.state.down ? 'down' : 'up'}
                    refreshing={this.state.refreshing}
                    onRefresh={() => {
                        this.setState({ refreshing: true });
                        setTimeout(() => {
                            this.setState({
                                refreshing: false
                            });

                        }, 1000);
                    }}
                >
                    <Slider></Slider>
                    {
                        all_stories.map((item, index) => {
                            return (
                                <div className="list-box" key={index}>
                                    <ul key={item.date}>
                                        <h2 className="title">{filter.dateTime(item.date)}</h2>
                                        {
                                            item.stories.map(subItem =>
                                                <ListItem key={subItem.id} item={subItem}></ListItem>
                                            )
                                        }
                                    </ul>
                                </div>
                            )
                        })
                    }
                </PullToRefresh>
            </div>
        )
    }
}


