import React, { Component } from "react"
import { Link } from "react-router-dom"
import "../css/list-theme.scss"
import api from "../api"
import filter from "../util/filter"
import { connect } from "react-redux";
import { getThemeData, toggleSidebar } from "../redux/action";
import { ListItem } from "./list-item";
import { ListHeader } from "./list-header";
import { SideBar } from "./sidebar";
import {Toast} from "antd-mobile"
@connect(
    state => {
        return {
            theme_stories: state.content_list.theme_stories
        }
    }
)
export class ListTheme extends Component {
    componentWillMount() {
        let { dispatch, match } = this.props;
        let { loading } = this.props.theme_stories
        let themeId = match.params.id;
        dispatch(getThemeData(api.GET_THEME + themeId))
        if (loading) {
            Toast.loading('正在加载中...');
        } else {
            Toast.hide();
        }

    }
    componentDidUpdate() {
        let { dispatch, match } = this.props;
        let { loading } = this.props.theme_stories
        let themeId = match.params.id;
        dispatch(getThemeData(api.GET_THEME + themeId));
        window.sessionStorage.editors = JSON.stringify(this.props.theme_stories.editors)
        if (loading) {
            Toast.loading('正在加载中...');
        } else {
            Toast.hide();
        }
    }
    iconDisplay = () => {
        const { match } = this.props;
        if (math.params.id) {
            return false
        }
        else {
            return true
        }
    }
    title = () => {
        const { match } = this.props;
        switch (match.params.id) {
            case '13':
                return '日常心理学'
            case '12':
                return '用户推荐日报'
            case '3':
                return '电影日报'
            case '11':
                return '不许无聊'
            case '4':
                return '设计日报'
            case '5':
                return '大公司日报'
            case '6':
                return '财经日报'
            case '10':
                return '互联网安全'
            case '2':
                return '开始游戏'
            case '7':
                return '音乐日报'
            case '9':
                return '动漫日报'
            case '8':
                return '体育日报'
            default:
                return '首页'
        }
    }
    render() {
        let { dispatch, theme_stories } = this.props
        return (
            <div>
                <ListHeader title={this.title()} iconDisplay={this.iconDisplay} />
                <SideBar></SideBar>
                <div className="theme-list">
                    <img className="detail-img-box margin-top" src={theme_stories.image} />
                    <div className="detail-mask"></div>
                    <p className="detail-title">{theme_stories.description}</p>
                    <p className="detail-image-source">{theme_stories.imageSource}</p>

                    {/*<!--主编-->*/}
                    {(() => {
                        if (theme_stories.editors && theme_stories.editors.length > 0) {
                            return (
                                <Link to="/editor">
                                    <div className="editors-box">
                                        <p>主编</p>
                                        {theme_stories.editors.map(item =>
                                            <div key={'editor-' + item.id} className="editors-item" >
                                                <img src={filter.replaceUrl(item.avatar)} alt="" />
                                            </div>
                                        )
                                        }
                                    </div>
                                </Link>
                            )
                        }
                    })()}
                    {/*<!--列表-->*/}
                    <div className="list-box">
                        <ul>
                            {theme_stories.stories.map(item =>
                                <ListItem key={'theme-' + item.id} item={item}></ListItem>
                            )}
                        </ul>
                    </div>
                </div>
            </div>
        )
    }
}


