import React, { Component } from 'react'
import "../css/common-header.scss"
export class CommonHeader extends Component {
    goBack() {
        window.history.back()
    }
    render() {
        let { title } = this.props
        return (
            <div className="common-header">
                <div className="header-icon" onClick={this.goBack}><i className="iconfont icon-fanhui"></i></div>
                <div className="header-cont"><p>{title}</p></div>
            </div>
        )
    }
}


