import React, { Component } from "react";
import "../css/sidebar.scss"
import api from "../api";
import { BrowserRouter as Router, HashRouter, Route, Link } from "react-router-dom"
import { connect } from "react-redux";
import { getSidebarData, toggleSidebar } from "../redux/action"
@connect(
    state => {
        return {
            list: state.sidebar.list,
            active: state.sidebar.active
        }
    }
)
export class SideBar extends Component {
    componentDidMount() {
        let { dispatch } = this.props;
        dispatch(getSidebarData(api.THEMES))
    }
    toggleSidebar = () => {
        let { dispatch } = this.props
        dispatch(toggleSidebar())
    }
    componentDidUpdate() {

    }
    render() {
        let { dispatch, list, id } = this.props
        return (
            <div>
                <div className={this.props.active ? "sidebar-box show-sidebar" : "sidebar-box"}>

                    <div className="sidebar-header" onClick={this.toggleSidebar}>
                        <Link to="/login">
                            <div className="user">
                                <img src="http://7xqch8.com1.z0.glb.clouddn.com/4.pic_hd.jpg" alt="" />
                                <p>{sessionStorage.username ? sessionStorage.username : "未登录"}</p>
                            </div>
                        </Link>
                        <div className="function">
                            <div className="function-sub">
                                <i className="iconfont icon-shoucang"></i>
                                <p>我的收藏</p>
                            </div>
                            <div className="function-sub">
                                <i className="iconfont icon-xiazai"></i>
                                <p>离线下载</p>
                            </div>
                        </div>
                    </div>

                    <div className="sidebar-list">
                        <Link to={`/`} replace>
                            <p className="sidebar-list-first" onClick={this.toggleSidebar}><i className="iconfont icon-app_icons--"></i>首页</p>
                        </Link>
                        <ul className="sidebar-list-ul">
                            {list.map(item =>
                                <Link key={item.name} to={`/theme/${item.id}`}>
                                    <li className="sidebar-list-li" onClick={this.toggleSidebar}>
                                        <p>{item.name}</p>
                                        <div>+</div>
                                    </li>
                                </Link>
                            )}
                        </ul>
                    </div>
                </div>
                <div className={this.props.active ? "sidebar-mask" : ''} onClick={this.toggleSidebar}></div>
            </div>

        )
    }
}


