
const initState = {
    list: [],
    active: false
}


export const sidebarList = (state = initState, action) => {
    switch (action.type) {
        case 'GET_SIDEBAR_LIST':
            return {
                list: action.data.others
            }
            break;
        case 'GET_SIDEBAR_LIST_SUCCESS':
            return {
                list: action.data.THEMES.others,
                active: false
            }
            break;
        case 'TOGGLE_SIDEBAR':
            return Object.assign({}, state, {
                ...state,
                active: !state.active
            })
            break;
        default:
            return state
    }
}


