import React, { Component } from "react"
import { Link } from "react-router-dom"
import { InputItem, WhiteSpace, WingBlank, Button ,Toast} from 'antd-mobile';
import { CommonHeader } from "../components/common-header";
import "../css/login.scss"
import { sendCode } from "../redux/action"
import axios from "axios"
export class Login extends Component {
    state = {
        loginBtn: true,
        codeBtn: true,
        count: 60,
        sencodebtn1: "block",
        sencodebtn2: "none",
        phone: 1,
        status: 0,
        telcode: 0,
        username: ""
    }
    codeChange = (value) => {
        let myreg = /[0-9]{4}/;
        let { username } = this.state
        if (myreg.test(value)) {
            this.setState({
                telcode: value,
                status: ++status
            })
        }
        if (status == 2 && username) {
            this.setState({
                loginBtn: false
            })
        }
    }
    usernameChange = (value) => {
        let { username } = this.state
        if (value) {
            this.setState({
                username: value
            })
        }
        if (status == 2 && username) {
            this.setState({
                loginBtn: false
            })
        }
    }
    onChange = (value) => {
        let myreg = /^[1][3,4,5,7,8][0-9]{9}$/;
        let { username } = this.state
        this.setState({
            phone: value
        })
        if (myreg.test(value)) {
            this.setState({
                codeBtn: false,
                status: ++status
            })
        }
        if (status == 2 && username) {
            this.setState({
                loginBtn: false
            })
        }
    }
    sendcode = () => {
        let { dispatch } = this.props;
        let { count, phone } = this.state
        axios.post("http://47.93.229.151:4400/react/sendCode", { phone: phone })
        this.setState({
            sencodebtn1: "none",
            sencodebtn2: "block"
        })
        let timer = null;
        let that = this;
        timer = setInterval(function () {
            if (count > 1) {
                that.setState({
                    count: --count
                })
            } else {
                clearInterval(timer);
                that.setState({
                    sencodebtn1: "block",
                    sencodebtn2: "none"
                })
            }
        }, 1000)
    }
    login = () => {
        let { history } = this.props;
        let { phone, username, telcode } = this.state;
        axios.post("http://47.93.229.151:4400/react/login", { phone, username, telcode }).then(res => {
            if (res.data == 1) {
                Toast.success('登录成功!!!', 1);
                history.push("/");
                window.sessionStorage.username=username
            }else{
                Toast.fail('登录失败 !!!', 1);
            }
        })
    }
    render() {
        let { dispatch } = this.props
        let { codeBtn, count, sencodebtn1, sencodebtn2, loginBtn } = this.state
        return (
            <div>
                <CommonHeader title="登录"></CommonHeader>
                <div className="header"></div>
                <WingBlank> <p className="tel"> 手机号</p><InputItem placeholder="请输入手机号" className="phone" onChange={this.onChange} /></WingBlank>
                <WhiteSpace />
                <WingBlank><p className="telcodep"> 验证码</p><InputItem placeholder="请输入验证码" maxLength="4" type="number" className="telcode" onChange={this.codeChange} /></WingBlank><Button type="warning" inline className="telcodeBtn" disabled={codeBtn} onClick={this.sendcode} style={{ display: sencodebtn1 }}>发送验证码</Button><Button inline className="telcodeBtn" disabled style={{ "display": sencodebtn2 }}>倒计时{count}秒</Button><WhiteSpace />
                <WhiteSpace />
                <WingBlank><p>用户名</p> <InputItem placeholder="请输入用户名" onChange={this.usernameChange} /></WingBlank>
                <WhiteSpace />
                <WingBlank><Button type="primary" disabled={loginBtn} onClick={this.login}>登录</Button> </WingBlank>
            </div>
        )

    }
}


