import React, { Component } from "react"
import { Link } from "react-router-dom"
import { connect } from "react-redux"
import filter from "../util/filter"
import SwiperDemo from "./swiperdemo"

@connect(
    state => {
        return {
            slider: state.content_list.top_stories
        }
    }
)
export class Slider extends Component {
    render() {
        let { slider } = this.props
        const value = slider.map((item, index) => {
            return (
                <Link to={`/detail/${item.id}`} key={`slider-${item.id}`}>
                    <img src={item.image} alt="" key={index} className="slider-img"/>
                    <h1 className="slider-title">{item.title}</h1>
                    <div className="slider-mask"></div>
                </Link>

            )
        })
        return (
            <SwiperDemo id="banner" swiperOptions={{  direction: "horizontal",
            speed: 500,
            autoplay: 3000,
            slidesPerView: 'auto', 
            pagination : '.swiper-pagination',  
            paginationClickable :true,
            resistanceRatio:0
}}>
                {value}
            </SwiperDemo>
        )
    }
}


