import React, { Component } from "react"
import "../css/list-header.scss"

import { connect } from "react-redux";
import filter from "../util/filter"
import { toggleSidebar, changeMode } from "../redux/action";
@connect(
    state => {
        return {
            date: state.content_list.date,
            night_style:state.content_list.night_style
        }
    }
)
export class ListHeader extends Component {
    changeMode = () => {
        let { dispatch, night_style } = this.props
        dispatch(changeMode())
        if (night_style) {
            window.document.getElementById('app').className = ''
        } else {
            window.document.getElementById('app').className = 'night-style'
        }
    }
    render() {
        let { dispatch, title, iconDisplay } = this.props
        return (
            <div className="list-header">
                <div className="header-icon" onClick={() => { dispatch(toggleSidebar()) }}><i className="iconfont icon-gengduo" style={{ fontSize: 22 }}></i></div>
                <div className="header-cont"><p>{title}</p></div>
                {
                    (() => {
                        if (iconDisplay) {
                            return (
                                <div className="header-icon-wrap">
                                    <div className="header-icon"  ><i className="iconfont icon-tongzhi" style={{ fontSize: 22 }}></i></div>
                                    <div className="header-icon" onClick={this.changeMode}><i className="iconfont icon-gengduo1" style={{ fontSize: 22 }}></i></div>
                                </div>
                            )
                        }
                    })()
                }
            </div>
        )
    }
}


