const initState = {
    items: [{
        recommenders: []
    }],
    editors: []
}
export const recommenderData = (state = initState, action) => {
    switch (action.type) {
        case 'GET_RECOMMENDER_SUCCESS':
            return Object.assign({}, action.data)
            break;
        case 'INIT_RECOMMENDER':
            return Object.assign({}, initState)
            break;
        default:
            return state
    }
}


