import React, { Component } from "react"
import api from "../api"
import filter from "../util/filter"
import "../css/detail-header.scss"
import { connect } from "react-redux";
import { Link } from "react-router-dom"
import { fetchData, hideCollection, showCollection, hideShare, showShare } from "../redux/action"
import {Toast} from "antd-mobile"
@connect(
    state => {
        return {
            detail_content: state.detail_content
        }
    }
)
export class DetailHeader extends Component {
    componentWillMount() {
        let { dispatch } = this.props
        dispatch(fetchData(api.STORY_EXTRA + this.props.id))
        let { loading } = this.props.detail_content
        if (loading) {
            Toast.loading('正在加载中...');
        } else {
            Toast.hide();
        }
    }
    changeCollection = () => {
        let { dispatch } = this.props;
        let { collection } = this.props.detail_content
        if (collection) {
            dispatch(hideCollection())
        } else {
            dispatch(showCollection())
        }
    }
    changeShare = () => {
        let { dispatch } = this.props
        let { show_share } = this.props.detail_content
        if (show_share) {
            dispatch(hideShare())
        } else {
            dispatch(showShare())
        }
    }
    goBack() {
        window.history.back()
    }
    render() {
        let { comments, popularity, collection, show_share } = this.props.detail_content
        let id = this.props.id
        return (
            <div>
                <div className="detail-header">
                    <div className="header-icon" onClick={this.goBack}><i className="iconfont icon-fanhui"></i></div>
                    <div className="detail-cont"></div>
                    <div className="header-icon" onClick={this.changeShare}><i className="iconfont icon-fenxiang"></i></div>
                    <div className="header-icon" onClick={this.changeCollection}><i className={collection ? 'iconfont collection' : 'iconfont'}>&#xe61d;</i></div>
                    <Link to={'/comments/' + id}>
                        <div className="header-icon">
                            <i className="iconfont icon-pinglun"></i><span>{comments}</span>
                        </div>
                    </Link>
                    <div className="header-icon"><i className="iconfont icon-dianzan"></i><span>{filter.toK(popularity)}</span></div>
                </div>
                {(() => {
                    if (show_share) {
                        return (
                            <div className="mask" onClick={this.changeShare}>
                                <div className="share-box">
                                    <p className="share-title">分享</p>
                                    <div className="share-content">
                                        <div className="child"><div className="icon color-red"><i className="iconfont icon-weibo"></i></div><p>新浪微博</p></div>
                                        <div className="child"><div className="icon color-green-1"><i className="iconfont icon-weixin"></i></div><p>微信</p></div>
                                        <div className="child"><div className="icon color-green-2"><i className="iconfont" onClick={()=>shareTo('weixin')}>&#xe66a;</i></div><p>微信朋友圈</p></div>
                                        <div className="child"><div className="icon color-blue-1"><i className="iconfont">&#xe69c;</i></div><p>有道云笔记</p></div>
                                        <div className="child"><div className="icon color-blue-2"><i className="iconfont">&#xe614;</i></div><p>QQ</p></div>
                                        <div className="child"><div className="icon color-green-3"><i className="iconfont">&#xe695;</i></div><p>印象笔记</p></div>
                                    </div>
                                </div>
                            </div>
                        )
                    }
                })()}
            </div>
        )
    }
}



